const numbersToWords=S=>{const l=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(S<0x14)return l[S];if(S<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](S/0xa)]+(S%0xa?'\x20'+l[S%0xa]:'');if(S<0x3e8){const n=Math['floor'](S/0x64),H=S%0x64;return(0x1===n?'εκατό':0x2===n?'διακόσια':0x3===n?'τριακόσια':0x4===n?'τετρακόσια':0x5===n?'πεντακόσια':0x6===n?'εξακόσια':0x7===n?'επτακόσια':0x8===n?'οκτακόσια':0x9===n?'εννιακόσια':'')+(H?'\x20'+numbersToWords(H):'');}return S<0xf4240?numbersToWords(Math['floor'](S/0x3e8))+'\x20χιλιάδες'+(S%0x3e8?'\x20'+numbersToWords(S%0x3e8):''):numbersToWords(Math['floor'](S/0xf4240))+'\x20εκατομμύρια'+(S%0xf4240?'\x20'+numbersToWords(S%0xf4240):'');},numberToText=(S,l='money')=>{const H=Math['floor'](S),h=Math['round'](0x64*(S-H));let X=numbersToWords(H),J=h>0x0?numbersToWords(h):'';switch(l){case'money':return J?X+'\x20ευρώ\x20και\x20'+J+'\x20λεπτά':X+'\x20ευρώ';case'time':return J?X+'\x20ώρες\x20και\x20'+J+'\x20λεπτά':X+'\x20ώρες';default:return J?X+'\x20και\x20'+J:''+X;}};